<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        :root {
            --bg-color: #f4f7f9;
            --column-bg: #ebedf0;
            --card-bg: #ffffff;
            --text-main: #333;
            --text-muted: #666;
            --accent: #4a90e2;
            --danger: #e74c3c;
            --shadow: 0 2px 5px rgba(0,0,0,0.1);
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg-color);
            color: var(--text-main);
            margin: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
        }

        header {
            width: 100%;
            padding: 2rem 0;
            text-align: center;
            background: white;
            box-shadow: var(--shadow);
            margin-bottom: 2rem;
        }

        .input-container {
            display: flex;
            justify-content: center;
            gap: 10px;
            margin-bottom: 1rem;
        }

        #new-card {
            padding: 10px 15px;
            border: 2px solid #ddd;
            border-radius: 6px;
            width: 300px;
            font-size: 1rem;
            outline: none;
            transition: border-color 0.2s;
        }

        #new-card:focus {
            border-color: var(--accent);
        }

        #add-card {
            padding: 10px 20px;
            background-color: var(--accent);
            color: white;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            transition: opacity 0.2s;
        }

        #add-card:hover {
            opacity: 0.9;
        }

        .board {
            display: flex;
            gap: 20px;
            padding: 0 20px 40px 20px;
            align-items: flex-start;
            width: 100%;
            max-width: 1200px;
            box-sizing: border-box;
        }

        .column {
            background-color: var(--column-bg);
            border-radius: 8px;
            flex: 1;
            min-width: 250px;
            display: flex;
            flex-direction: column;
            min-height: 400px;
            transition: background-color 0.2s ease;
        }

        .column.drag-over {
            background-color: #dfe3e6;
            outline: 2px dashed var(--accent);
        }

        .column-header {
            padding: 15px;
            font-weight: bold;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid #ddd;
        }

        .count {
            background: #ccc;
            color: white;
            padding: 2px 8px;
            border-radius: 12px;
            font-size: 0.8rem;
        }

        .card-container {
            padding: 10px;
            flex-grow: 1;
            min-height: 100px;
        }

        .card {
            background: var(--card-bg);
            border-radius: 6px;
            padding: 15px;
            margin-bottom: 10px;
            box-shadow: var(--shadow);
            cursor: grab;
            display: flex;
            justify-content: space-between;
            align-items: center;
            word-break: break-word;
            transition: transform 0.1s ease;
        }

        .card:active {
            cursor: grabbing;
        }

        .card:hover {
            transform: translateY(-2px);
        }

        .card-text {
            flex-grow: 1;
            margin-right: 10px;
            font-size: 0.95rem;
        }

        .card-del {
            background: none;
            border: none;
            color: var(--text-unset);
            color: #aaa;
            font-size: 1.2rem;
            cursor: pointer;
            line-height: 1;
            padding: 0 5px;
        }

        .card-del:hover {
            color: var(--danger);
        }

        @media (max-width: 768px) {
            .board {
                flex-direction: column;
                align-items: center;
            }
            .column {
                width: 100%;
            }
        }
    </style>
</head>
<body>

<header>
    <h1>Kanban Board</h1>
    <div class="input-container">
        <input type="text" id="new-card" placeholder="Enter task title..." autocomplete="off">
        <button id="add-card">Add Task</button>
    </div>
    <p style="font-size: 0.8rem; color: #888;">Drag cards between columns to update status.</p>
</header>

<div class="board">
    <!-- To Do Column -->
    <div id="col-todo" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            <span>To Do</span>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>

    <!-- Doing Column -->
    <div id="col-doing" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            <span>Doing</span>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>

    <!-- Done Column -->
    <div id="col-done" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            <span>Done</span>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>
</div>

<script>
    // --- State Management ---
    let cards = JSON.parse(localStorage.getItem('kanban-cards')) || [];

    function saveState() {
        localStorage.setItem('kanban-cards', JSON.stringify(cards));
    }

    // --- DOM Elements ---
    const inputField = document.getElementById('new-card');
    const addButton = document.getElementById('add-card');
    const columns = ['col-todo', 'col-card-container', 'col-doing', 'col-done']; // Helper list for logic

    // --- Core Functions ---

    function render() {
        // Clear all containers and reset counts
        const columnIds = ['col-todo', 'col-doing', 'col-done'];

        columnIds.forEach(id => {
            const colEl = document.getElementById(id);
            const container = colEl.querySelector('.card-container');
            const countEl = colEl.querySelector('.count');

            // Clear existing cards in DOM
            container.innerHTML = '';

            // Calculate count for this column from state
            const count = cards.filter(c => c.colId === id).length;
            countEl.textContent = count;
        });

        // Re-populate cards from state
        cards.forEach(card => {
            const cardElement = createCardElement(card);
            const targetCol = document.getElementById(card.colId).querySelector('.card-container');
            targetCol.appendChild(cardElement);
        });
    }

    function createCardElement(cardData) {
        const div = document.createElement('div');
        div.className = 'card';
        div.draggable = true;
        div.dataset.id = cardData.id;

        // Drag Start Handler
        div.addEventListener('dragstart', (e) => {
            e.dataTransfer.setData('text/plain', cardData.id);
            // Small delay to allow the drag ghost image to be created before opacity changes
            setTimeout(() => div.style.opacity = '0.5', 0);
        });

        div entListener('dragend', () => {
            div.style.opacity = '1';
        });

        // Card Content
        const textSpan = document.createElement('span');
        textSpan.className = 'card-text';
        textSpan.textContent = cardData.text;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.innerHTML = '&times;';
        delBtn.onclick = () => deleteCard(cardData.id);

        div.appendChild(textSpan);
        div.appendChild(delBtn);

        return div;
    }

    function addCard() {
        const text = inputField.value.trim();
        if (!text) return;

        const newCard = {
            id: Date.now().toString(),
            text: text,
            colId: 'col-todo'
        };

        cards.push(newCard);
        saveState();
        render();
        inputField.value = '';
    }

    function deleteCard(id) {
        cards = cards.filter(c => c.id !== id);
        saveState();
        render();
    }

    // --- Drag and Drop Handlers ---

    function handleDragOver(e) {
        e.preventDefault(); // Required to allow drop
        const column = e.currentTarget;
        if (!column.classList.contains('drag-over')) {
            column.classList.add('drag-over');
        }
    }

    function handleDragLeave(e) {
        e.currentTarget.classList.remove('drag-over');
    }

    function handleDrop(e) {
        e.preventDefault();
        const column = e.currentTarget;
        column.classList.remove('drag-over');

        const cardId = e.dataTransfer.getData('text/plain');
        const targetColId = column.id;

        // Update the state
        const cardIndex = cards.findIndex(c => c.id === cardId);
        if (cardIndex !== -1) {
            cards[cardIndex].colId = targetColId;
            saveState();
            render();
        }
    }

    // --- Event Listeners ---

    addButton.addEventListener('click', addCard);

    inputField.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') addCard();
    });

    // Initial Render
    render();

</script>

</body>
</html>
